export type ClickStatus = 'live' | 'parked' | 'concluded' | 'dropped';

export type LinkType = 'related' | 'commissioned' | 'supersedes' | 'depends-on';

/**
 * A single entry in a click's `goalHistory`. Each entry captures the prior
 * goal text at the moment an amend supplanted it, the ISO timestamp of that
 * amend, and — when supplied — the session that performed it. Entries are
 * appended chronologically; the newest entry is always last in the array.
 */
export interface GoalHistoryEntry {
  /** The goal text that was replaced by this amend. */
  goal: string;
  /** ISO timestamp at which the amend occurred. */
  amendedAt: string;
  /** Session id that performed the amend, when supplied. */
  sessionId?: string;
}

export interface ClickDoc {
  [key: string]: unknown;
  id: string;
  parentId?: string;
  goal: string;
  /**
   * Prior goal values preserved by `amend()`, oldest-first. Absent on records
   * created before the amend affordance was introduced; readers must treat
   * missing and empty as "no amends yet."
   */
  goalHistory?: GoalHistoryEntry[];
  status: ClickStatus;
  conclusion?: string;
  createdSessionId?: string;
  resolvedSessionId?: string;
  createdAt: string;
  resolvedAt?: string;
}

export interface ClickLinkDoc {
  [key: string]: unknown;
  id: string;
  sourceId: string;
  targetId: string;
  linkType: LinkType;
  createdAt: string;
}

export interface ClickLinks {
  outbound: ClickLinkDoc[];
  inbound: ClickLinkDoc[];
}

export interface CreateClickRequest {
  goal: string;
  parentId?: string;
  createdSessionId?: string;
}

export interface ConcludeClickRequest {
  conclusion: string;
  resolvedSessionId?: string;
}

export interface DropClickRequest {
  conclusion: string;
  resolvedSessionId?: string;
}

export interface ReparentClickRequest {
  parentId?: string | null;
}

export interface AmendClickRequest {
  /** The new goal text. Empty or whitespace-only text is rejected. */
  goal: string;
  /** Session id performing the amend, recorded on the history entry. */
  sessionId?: string;
}

export interface SupersedeClickRequest {
  /**
   * Goal text for the newly created click. Empty or whitespace-only text is
   * rejected, matching `create()`.
   */
  goal: string;
  /** Optional parent for the new click. When omitted the new click is a root. */
  parentId?: string;
  /** Session id that created the new click. */
  createdSessionId?: string;
}

export interface LinkClickRequest {
  sourceId: string;
  targetId: string;
  linkType: LinkType;
}

export interface UnlinkClickRequest {
  sourceId: string;
  targetId: string;
  linkType: LinkType;
}

export interface ExtractClickRequest {
  format: 'md' | 'json';
  full?: boolean;
  depth?: number;
}

export interface ClickFilters {
  status?: ClickStatus | ClickStatus[];
  parentId?: string;
  rootId?: string;
  limit?: number;
  offset?: number;
}

/**
 * A single entry in a `ClickTree` supersede reference array. Each entry
 * names the referenced click by id and carries a `goal` snippet to let
 * downstream renderers (markdown, text tree) format a link line without
 * a second fetch.
 *
 * When the referenced click cannot be fetched (e.g. deleted, stale link),
 * `goal` is `null` and renderers should emit a `<missing>` placeholder.
 *
 * Inbound (`supersededBy`) entries may carry an optional `chain` of
 * intermediate short-ids walked between the host node and the terminal
 * superseder — populated only when the inbound supersede chain is longer
 * than one hop. `id` and `goal` always describe the *terminal* superseder
 * for the chain; `chain` (when present) lists the short-ids of the
 * intermediate hops in walk order (excluding the host and the terminal).
 */
export interface SupersedeRef {
  id: string;
  goal: string | null;
  chain?: string[];
}

export interface ClickTree {
  click: ClickDoc;
  children: ClickTree[];
  /**
   * Inbound `supersedes` links — i.e. clicks that supersede *this* click.
   * Populated by `ratchet.tree()` / `ratchet.extract()` enrichment; each
   * entry represents one immediate inbound superseder, with its chain
   * walked to the terminal (cycle-safe, branch-terminating). Absent when
   * the click has no inbound supersedes.
   */
  supersededBy?: SupersedeRef[];
  /**
   * Outbound `supersedes` links — i.e. clicks that *this* click supersedes.
   * Populated by `ratchet.tree()` / `ratchet.extract()` enrichment as one
   * immediate predecessor per edge (one hop). Absent when the click has
   * no outbound supersedes.
   */
  supersedes?: SupersedeRef[];
}

export interface TreeParams {
  rootId?: string;
  status?: ClickStatus | ClickStatus[];
  depth?: number;
}

export interface RatchetApi {
  create(params: CreateClickRequest): Promise<ClickDoc>;
  get(id: string): Promise<ClickDoc>;
  list(filters?: ClickFilters): Promise<ClickDoc[]>;
  park(id: string): Promise<ClickDoc>;
  resume(id: string): Promise<ClickDoc>;
  conclude(id: string, params: ConcludeClickRequest): Promise<ClickDoc>;
  drop(id: string, params: DropClickRequest): Promise<ClickDoc>;
  reparent(id: string, params: ReparentClickRequest): Promise<ClickDoc>;
  amend(id: string, params: AmendClickRequest): Promise<ClickDoc>;
  /**
   * Atomically create a new click and a `supersedes` link from the new click
   * to `targetId`. Both writes land inside a single Stacks transaction; if
   * either fails, neither is persisted. The target may be in any status —
   * `live`, `parked`, `concluded`, or `dropped` — and is not reparented. The
   * new click's default parent is unset (root); pass `params.parentId` to
   * nest it. Returns both documents.
   */
  supersede(
    targetId: string,
    params: SupersedeClickRequest,
  ): Promise<{ click: ClickDoc; link: ClickLinkDoc }>;
  link(params: LinkClickRequest): Promise<ClickLinkDoc>;
  unlink(params: UnlinkClickRequest): Promise<void>;
  extract(rootId: string, params: ExtractClickRequest): Promise<string | ClickTree>;
  tree(params?: TreeParams): Promise<ClickTree[]>;
  resolveId(prefix: string): Promise<string>;
  links(clickId: string): Promise<ClickLinks>;

  /**
   * Count all descendants of a click grouped by status.
   *
   * Walks the parent/child tree recursively beneath `clickId`, tallying each
   * descendant's status. The root click (the click identified by `clickId`)
   * is excluded from the count — only its descendants contribute. The result
   * is a plain object keyed by `ClickStatus` with numeric values; statuses
   * with no matching descendants are simply absent.
   *
   * This is the traversal primitive behind `click-show`'s `children.summary`
   * field. Mirrors the shape of `ClerkApi.countDescendantsByPhase`.
   * Throws if the click does not exist.
   */
  countDescendantsByStatus(clickId: string): Promise<Record<ClickStatus, number>>;
}

/**
 * Reckoner public types.
 *
 * The Reckoner is the petitioner-scheduler apparatus. It owns the
 * kit-static petitioner registry, exposes the canonical
 * `petition()` / `withdraw()` helpers (Workflow 2 in the contract
 * document), and surfaces inspection helpers for downstream
 * consumers (the periodic tick handler, the vision-keeper kit, the
 * patron-bridge apparatus).
 *
 * This file is the single source of public-symbol truth — every
 * type a downstream import touches lives here, including
 * `ReckonerApi`. The factory in `./reckoner.ts` builds a value
 * matching `ReckonerApi`; see that module for how `provides` is
 * assembled.
 *
 * See: docs/architecture/petitioner-registration.md  (the load-
 * bearing contract document) and
 * docs/architecture/apparatus/reckoner.md (the apparatus shape).
 */

import type { WritDoc } from '@shardworks/clerk-apparatus';

// ── Priority ──────────────────────────────────────────────────────────

/**
 * The five-dimensional priority shape declared on every petition.
 *
 * Each dimension answers a different question; the Reckoner
 * combines them at consideration time. See §3 of the contract
 * document for the semantics of every value.
 */
export interface Priority {
  /** Relationship to the product vision (vision-blocker, vision-violator, vision-advancer, vision-neutral). */
  visionRelation:
    | 'vision-blocker'
    | 'vision-violator'
    | 'vision-advancer'
    | 'vision-neutral';
  /** Magnitude axis (critical, serious, moderate, minor). */
  severity: 'critical' | 'serious' | 'moderate' | 'minor';
  /** What fraction of the system is affected (whole-product, major-area, minor-area). */
  scope: 'whole-product' | 'major-area' | 'minor-area';
  /** Two genuinely-independent time-pressure axes. */
  time: {
    /** Drift sentinel / accumulating-debt flag. */
    decay: boolean;
    /** Hard deadline if any (ISO date string), else `null`. */
    deadline: string | null;
  };
  /** Multi-valued classification tag set. NOT a priority axis — describes what kind of work this is. */
  domain: Array<
    | 'security'
    | 'compliance'
    | 'cost'
    | 'feature'
    | 'quality'
    | 'infrastructure'
    | 'documentation'
    | 'research'
    | 'ergonomics'
  >;
}

/** Allowed values for `Priority.visionRelation`. */
export const VISION_RELATION_VALUES = [
  'vision-blocker',
  'vision-violator',
  'vision-advancer',
  'vision-neutral',
] as const;

/** Allowed values for `Priority.severity`. */
export const SEVERITY_VALUES = [
  'critical',
  'serious',
  'moderate',
  'minor',
] as const;

/** Allowed values for `Priority.scope`. */
export const SCOPE_VALUES = [
  'whole-product',
  'major-area',
  'minor-area',
] as const;

/** Allowed values for `Priority.domain[]`. */
export const DOMAIN_VALUES = [
  'security',
  'compliance',
  'cost',
  'feature',
  'quality',
  'infrastructure',
  'documentation',
  'research',
  'ergonomics',
] as const;

// ── Complexity ────────────────────────────────────────────────────────

/**
 * Petitioner-side coarse cost estimate. See §4 of the contract
 * document for the calibration ranges. Refined by the Astrolabe at
 * plan time; this exists for early-stage trade-offs only.
 */
export type ComplexityTier =
  | 'mechanical'
  | 'bounded'
  | 'exploratory'
  | 'open-ended';

// ── Reckoner ext shape ────────────────────────────────────────────────

/**
 * Shape of `writ.ext['reckoner']` — the contract slot a petitioner
 * stamps onto a writ to opt it into Reckoner consideration.
 *
 * The Reckoner sweeps the writs book on every periodic tick and
 * treats every writ carrying this slot in `new` phase as a held
 * petition. Petitioners can stamp it directly via `clerk.post()` +
 * `clerk.setWritExt()` (Workflow 1) or use the `petition()` helper
 * (Workflow 2) for default-fill and validation; both paths produce
 * the same on-disk shape.
 */
export interface ReckonerExt {
  /** Identifies the petitioner. Must be `{pluginId}.{kebab-suffix}`. */
  source: string;
  /** Fully-defaulted multi-dimensional priority. */
  priority: Priority;
  /** Optional petitioner-side coarse cost estimate. */
  complexity?: ComplexityTier;
  /** Opaque petitioner-defined data; the Reckoner stores but does not introspect. */
  payload?: unknown;
  /** Additive non-priority metadata (multi-instance discrimination, observability hints). */
  labels?: Record<string, string>;
}

// ── Petition request ──────────────────────────────────────────────────

/**
 * Ext-only argument shape — the `writ.ext['reckoner']` fields a
 * petitioner supplies, decoupled from the writ-shape fields.
 *
 * Used as the second argument to the stamp-only form of
 * `ReckonerApi.petition(writId, extRequest)` (the draft-then-publish
 * idiom: post a writ in its initial phase without `ext.reckoner`,
 * wire dependencies, then stamp `ext.reckoner` to publish). The
 * create+stamp form of `petition()` accepts a `PetitionRequest`
 * which extends this shape with the writ-shape fields.
 *
 * The helper takes a partial priority — every omitted dimension is
 * filled with the contract default at the helper boundary (D15) so
 * petitioners with one strongly-felt dimension do not need to
 * supply the entire shape.
 */
export interface PetitionExtRequest {
  /** Petitioner source id. Required. Matched against the registry. */
  source: string;
  /** Partial priority — omitted dimensions fall back to defaults at the helper boundary. */
  priority?: Partial<Priority>;
  /** Optional coarse complexity estimate. */
  complexity?: ComplexityTier;
  /** Opaque petitioner-defined data. */
  payload?: unknown;
  /** Additive metadata labels. */
  labels?: Record<string, string>;
}

/**
 * Argument shape for the create+stamp form of `ReckonerApi.petition()`.
 *
 * Extends `PetitionExtRequest` with the writ-shape fields that pass
 * straight through to `clerk.post()`. The optional `type` mirrors
 * `PostCommissionRequest.type?` exactly — when omitted, the guild's
 * default writ type is used (D21).
 */
export interface PetitionRequest extends PetitionExtRequest {
  // ── writ fields (passed through to clerk.post) ───────────────────
  /** Writ type. Defaults to the guild's configured default writ type. */
  type?: string;
  /** Short human-readable title describing the petition. */
  title: string;
  /** Detail text. */
  body: string;
  /** Optional target codex name. */
  codex?: string;
  /** Create this writ as a child of the specified parent writ. */
  parentId?: string;
}

// ── Petitioner descriptor ─────────────────────────────────────────────

/**
 * Kit-contributed petitioner descriptor.
 *
 * Petitioners declare themselves via a `petitioners` kit
 * contribution — an array of these objects under that key on a kit
 * (or apparatus supportKit). The Reckoner consumes the array at
 * boot, validates each entry's source-id grammar, and seals the
 * registry at `phase:started`.
 *
 * The contract floor is intentionally minimal (D19, patron
 * override): only `source` and `description`. Enrichment fields
 * (contributing plugin id, timestamps, etc.) wait for a named
 * consumer.
 */
export interface PetitionerDescriptor {
  /** Fully-qualified source id of the form `{pluginId}.{kebab-suffix}`. */
  source: string;
  /** Human-readable description of what this petitioner emits. */
  description: string;
}

// ── Reckonings record ────────────────────────────────────────────────

/**
 * Outcome enum for a Reckonings record. The tick handler emits
 * `'accepted'` (after a successful `new → active` transition),
 * `'declined'` (after a `new → cancelled` transition driven by the
 * source-unregistered, source-banned, or scheduler-decline path),
 * and `'deferred'` (when the active scheduler returns a `defer`
 * decision; the writ stays in `new`). The fourth value, `'no-op'`,
 * is reserved for future commissions.
 *
 * See: docs/architecture/reckonings-book.md §"Outcome enum".
 */
export type ReckoningOutcome = 'accepted' | 'deferred' | 'declined' | 'no-op';

/**
 * Decline-reason enum for a Reckonings record with `outcome: 'declined'`.
 * The v0 handler emits only `'source_unregistered'`; the wider set is
 * declared here so consumer types can pattern-match without drifting
 * when later commissions add reason paths.
 *
 * See: docs/architecture/reckonings-book.md §"Decline reasons".
 */
export type ReckoningDeclineReason =
  | 'malformed'
  | 'duplicate'
  | 'policy_violation'
  | 'source_banned'
  | 'source_unregistered'
  | 'other';

/**
 * Defer-reason enum for a Reckonings record with `outcome: 'deferred'`.
 *
 * The `dependency_pending` and `dependency_failed` reasons are emitted
 * by the dependency-aware consideration gate (D1–D13 of the
 * dependency-aware-consideration commission): a held petition with one
 * or more outbound `depends-on` links whose targets are not all
 * `cleared` (terminal + success-or-cancelled attrs) is left in `new`
 * phase and a deferred Reckonings row is written. `dependency_failed`
 * carries failed-precedence — when at least one dependency target
 * resolves to a `failed` classification, the gate emits
 * `dependency_failed` regardless of how many other deps are still
 * gating. The scheduler-emitted defer path now writes deferred rows
 * with `'other'` as the reason (the decision's lineage string lands
 * in `deferNote`). The remaining values (`priority`, `queue_depth`,
 * `time_hold`, `patron_policy`) remain reserved for future
 * commissions.
 *
 * See: docs/architecture/reckonings-book.md §"Defer reasons" and
 * docs/architecture/apparatus/reckoner.md §"Dependency-aware defer".
 */
export type ReckoningDeferReason =
  | 'priority'
  | 'queue_depth'
  | 'time_hold'
  | 'patron_policy'
  | 'dependency_pending'
  | 'dependency_failed'
  | 'other';

/**
 * Vision-relation projection on a Reckonings record. Mirrors the
 * `Priority.visionRelation` enum exactly — projected at the top level
 * of the record so the per-vision-relation timeline index can name it
 * directly.
 */
export type ReckoningVisionRelation = Priority['visionRelation'];

/**
 * Severity projection on a Reckonings record. Mirrors the
 * `Priority.severity` enum exactly — projected at the top level of
 * the record so the per-severity timeline index can name it directly.
 */
export type ReckoningSeverity = Priority['severity'];

/**
 * One row in the Reckonings book — the Reckoner's evaluation journal.
 *
 * Every meaningful consideration produces one record. A record
 * with `outcome: 'accepted'` corresponds to a `new → active` phase
 * transition; `'declined'` to a `new → cancelled` transition; the
 * other two outcomes are reserved for future commissions.
 *
 * The flat optional layout (every reason field at the top level)
 * intentionally trades type-purity for index-friendliness — the
 * architecture doc notes the iff-outcome invariant is writer-enforced
 * by the Reckoner and consumer types decode against a discriminated
 * union. See `docs/architecture/reckonings-book.md` §"Record body".
 */
export interface ReckoningDoc {
  /** Index signature required to satisfy the Stacks `BookEntry` constraint. */
  [key: string]: unknown;
  /** Unique id (`rk-<base36_ts>-<hex>`). Sortable by creation time. */
  id: string;
  /** The Clerk writ this record is about (the held petition). */
  writId: string;
  /**
   * Forward-compatible extension to the contract shape: the
   * triggering writ's `updatedAt` value, captured at consideration
   * time. Used for the `(writId, writUpdatedAt)` dedupe identity
   * (D6/D23). Not declared in `reckonings-book.md`'s illustrative
   * schema; the doc's "every meaningful field named and filterable"
   * ethos justifies storing it as a top-level field rather than
   * burying it under a context blob.
   */
  writUpdatedAt: string;
  /** Lean projection: `ext.reckoner.source`. */
  source: string;
  /** Lean projection: `ext.reckoner.priority.visionRelation`. */
  visionRelation: ReckoningVisionRelation;
  /** Lean projection: `ext.reckoner.priority.severity`. */
  severity: ReckoningSeverity;
  /** Outcome enum — drives the discriminated-union reason fields. */
  outcome: ReckoningOutcome;
  /**
   * Triggering Clockworks event id, stamped from the
   * `clockworks.timer` event the standing-order dispatch handed to
   * the tick relay. Populated whenever the relay handler receives a
   * non-null event with an id; omitted on test paths driving the
   * pure tick helper directly with `null`. Synthesizing a fallback
   * id would pollute rows with non-joinable values; absence is
   * meaningful and is what test rows look like.
   */
  tickEventId?: string;
  /** ISO timestamp when the Reckoner completed this consideration. */
  consideredAt: string;
  // ── Outcome-keyed reason metadata (flat optionals, writer-enforced) ──
  /** Populated iff `outcome === 'declined'`. */
  declineReason?: ReckoningDeclineReason;
  /** Optional remediation hint accompanying a decline. */
  remediationHint?: string;
  /** Populated iff `outcome === 'deferred'`. */
  deferReason?: ReckoningDeferReason;
  /** Optional defer-until ISO timestamp. */
  deferUntil?: string;
  /** Optional defer wake-up event pattern. */
  deferSignal?: string;
  /** Running deferral counter for this writ. */
  deferCount?: number;
  /** First-seen-as-deferred ISO timestamp. */
  firstDeferredAt?: string;
  /** Most-recent deferral ISO timestamp. */
  lastDeferredAt?: string;
  /** Optional freeform short note on a deferral. */
  deferNote?: string;
  /**
   * Optional scheduler-emitted weight projected onto the row when a
   * `SchedulerDecision` carried one. Forward-compatible with
   * future weighted-priority schedulers; absent for the v0
   * always-approve scheduler. The Reckoner's row writer threads the
   * value through verbatim — no normalization, no defaulting.
   */
  weight?: number;
}

// ── Scheduler ─────────────────────────────────────────────────────────

/**
 * A held writ — a writ in `new` phase carrying `ext.reckoner`.
 *
 * Vocabulary alias for `WritDoc` used at scheduler-input read sites
 * to make intent explicit. There is no runtime invariant beyond what
 * the apparatus already guarantees at the call site (phase + ext
 * gates run before the scheduler is invoked); the alias is purely
 * documentary so a reader of `SchedulerInput` knows the candidate
 * shape without chasing back through the rule sequence.
 */
export type HeldWrit = WritDoc;

/**
 * Forward-compatible capacity slot threaded into `SchedulerInput`.
 *
 * Empty in v0 — the slot exists so the scheduler interface does not
 * have to grow a new positional argument when a future commission
 * adds capacity tracking (concurrent-active counts, per-source
 * quotas, queue-depth observations). Schedulers that do not consume
 * capacity simply ignore the field.
 */
export interface CapacitySnapshot {
  /** Reserved for future capacity-tracking commissions. v0 ships no fields. */
  [key: string]: unknown;
}

/**
 * The outcome a scheduler emits for a held writ. Mirrors the three
 * substantive Reckonings outcomes:
 *
 * - `'approve'` — drive the writ out of `new` to its type's active
 *   target and append an `accepted` Reckonings row.
 * - `'defer'`   — leave the writ in `new`. No transition, no row
 *   in v0 (deferred rows require richer reason metadata than the
 *   `SchedulerDecision` shape declares).
 * - `'decline'` — drive the writ to `cancelled` with the decision's
 *   `reason` recorded as the resolution string and append a
 *   `declined` Reckonings row carrying `declineReason: 'other'` plus
 *   the reason in `remediationHint`.
 */
export type SchedulerOutcome = 'approve' | 'defer' | 'decline';

/**
 * One scheduler decision targeting one held writ.
 *
 * `writId` identifies the candidate; `outcome` selects the
 * disposition; `reason` is a human-readable lineage string the
 * apparatus persists alongside the decision (resolution string for
 * declines, `remediationHint` for declined Reckonings rows, or a
 * grep-able marker on accepted rows). `weight` is an optional
 * scheduler-emitted score the apparatus threads onto the resulting
 * Reckonings row when present.
 */
export interface SchedulerDecision {
  /** The held writ this decision applies to. Must match a candidate from the input. */
  writId: string;
  /** The scheduler's selected outcome. */
  outcome: SchedulerOutcome;
  /** Human-readable lineage. Persisted on Reckonings rows where applicable. */
  reason: string;
  /** Optional scheduler-emitted weight. Threaded through to the Reckonings row when present. */
  weight?: number;
}

/**
 * Argument shape for `Scheduler.evaluate()`.
 *
 * The Reckoner samples `now` once at the call boundary so the row id
 * and `consideredAt` stay consistent within a single consideration
 * (D33). `config` is the validated, scheduler-narrowed view of the
 * `reckoner.schedulerConfig` block — the apparatus runs
 * `validateConfig` immediately before each `evaluate` call (D17) so
 * each invocation sees the freshest config.
 */
export interface SchedulerInput<TConfig = unknown> {
  /** The held writs the scheduler is being asked to consider. */
  candidates: readonly HeldWrit[];
  /** Forward-compatible capacity slot. Empty in v0. */
  capacity: CapacitySnapshot;
  /** Sampling timestamp from the apparatus call boundary. */
  now: Date;
  /** Validated config slice — narrowed by `Scheduler.validateConfig` when present. */
  config: TConfig;
}

/**
 * A scheduler — pluggable selection policy contributed via the
 * `schedulers` kit-contribution type.
 *
 * Each registered scheduler declares an `id` of the form
 * `{contributingPluginId}.{kebab-suffix}`, a human-readable
 * `description`, an `evaluate` function that takes a
 * `SchedulerInput` and returns one or more `SchedulerDecision`s, and
 * an optional `validateConfig` narrower the apparatus calls per
 * evaluation when the operator has supplied a `reckoner.schedulerConfig`
 * block. The Reckoner resolves a single active scheduler at startup
 * from `guild.json reckoner.scheduler` (defaults to
 * `reckoner.always-approve` when unset).
 *
 * Schedulers reach for shared guild state (Stacks book handles, Clerk
 * helpers) via `guild()` rather than constructor injection — the
 * direct-instance shape mirrors Fabricator's `EngineDesign` registry
 * precedent.
 */
export interface Scheduler<TConfig = unknown> {
  /** Fully-qualified id of the form `{pluginId}.{kebab-suffix}`. */
  id: string;
  /** Human-readable description of the scheduling policy. */
  description: string;
  /** Run the policy against the candidate set and emit decisions. */
  evaluate(input: SchedulerInput<TConfig>): Promise<readonly SchedulerDecision[]>;
  /**
   * Optional config narrower. Called per evaluation immediately
   * before `evaluate`; throws are caught by the apparatus, logged
   * fail-loud, and skip the call without writing a row or
   * transitioning the writ.
   */
  validateConfig?(raw: unknown): TConfig;
}

// ── Reckoner config ───────────────────────────────────────────────────

/**
 * Reckoner apparatus configuration — lives under the `reckoner`
 * key in `guild.json`.
 *
 * Both fields are optional. Missing config is treated as defaults
 * (`enforceRegistration: false`, `disabledSources: []`). When the
 * block is present, type mismatches throw fail-loud at the read
 * site (D12).
 */
export interface ReckonerConfig {
  /**
   * Controls how the Reckoner handles petitions whose source is
   * not in the registry. `false` (default) — log a warning and
   * proceed. `true` — decline the petition fail-loud at the
   * helper boundary.
   */
  enforceRegistration?: boolean;
  /**
   * Per-source disable list. Petitions from any source in this
   * array are skipped (left in `new` phase). The list is re-read
   * on each call so operators can hot-edit `guild.json` without a
   * restart (D20).
   */
  disabledSources?: string[];
  /**
   * Selector for the active scheduler. Must match a registered
   * `Scheduler.id`; resolved once at `phase:started` and cached for
   * the seal's life. When unset, defaults to the built-in
   * `reckoner.always-approve` scheduler. When set to an unknown id,
   * the Reckoner fail-loud throws at startup with a diagnostic
   * listing every registered id.
   */
  scheduler?: string;
  /**
   * Opaque per-evaluation config slice passed into the active
   * scheduler. Re-read from `guild.json` on every consideration so
   * operators can hot-edit (D17) without a restart. The Reckoner
   * does not narrow this value — each scheduler's `validateConfig`
   * is the boundary.
   */
  schedulerConfig?: unknown;
}

// Augment GuildConfig so `guild().guildConfig().reckoner` is typed
// without requiring a manual type parameter at the call site.
declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    reckoner?: ReckonerConfig;
  }
}

// ── API surface ───────────────────────────────────────────────────────

/**
 * The Reckoner's runtime API — retrieved via
 * `guild().apparatus<ReckonerApi>('reckoner')`.
 *
 * The surface is a coherent set of helpers for petitioner authoring
 * (`petition`, `withdraw`) and registry inspection
 * (`isSourceRegistered`, `isSourceDisabled`, `listPetitioners`).
 * The periodic tick handler consumes the inspection helpers
 * per-tick; the petitioner authoring helpers are the canonical
 * Workflow-2 path for petitioners.
 */
export interface ReckonerApi {
  /**
   * Create + stamp form. Post a writ in its registered initial
   * phase with `writ.ext['reckoner']` set correctly.
   *
   * Resolves the source against the registry. When the source is
   * not registered:
   *   - `enforceRegistration: true` — throws fail-loud, no writ
   *     is created.
   *   - `enforceRegistration: false` (default) — logs a warning
   *     and proceeds.
   *
   * Validates every priority dimension against its enum. Applies
   * defaults to omitted priority dimensions (field-by-field
   * merge). Delegates to the stamp-only form below for the actual
   * ext write — source/priority validation runs once via the
   * shared internal helper consumed by both forms, so a malformed
   * input never produces an orphan writ.
   *
   * Returns the resulting writ document (post-`setWritExt`, so
   * `writ.ext.reckoner` is populated on the returned shape).
   */
  petition(request: PetitionRequest): Promise<WritDoc>;

  /**
   * Stamp-only form — the draft-then-publish idiom. Stamps
   * `writ.ext['reckoner']` onto an already-posted writ that is
   * still in its writ-type's initial phase, making the writ
   * Reckoner-visible. Mirrors the create+stamp form's source-
   * registry, priority-default-fill, and dimension-validation
   * semantics; differs only in that the caller has already
   * posted the writ (typically so dependencies via `clerk.link()`
   * could be wired before consideration).
   *
   * Guards (in order; each fails loud with a `[reckoner] petition:`
   * prefix and produces no writ mutation):
   *   1. source registry + `enforceRegistration` (same as create+stamp).
   *   2. priority dimension validation (same as create+stamp).
   *   3. writ exists (`clerk.show(writId)` throws otherwise).
   *   4. writ is in its type's initial phase (`clerk.isInitial(writ)`).
   *   5. `writ.ext.reckoner` is absent — petitioning is a one-time
   *      act; an already-petitioned writ never silently re-stamps.
   *
   * Composes naturally with `stacks.transaction(...)`: when the
   * petitioner wraps `clerk.post() + clerk.link() + reckoner.petition(
   * writId, ext)` in a single transaction, the writ becomes
   * Reckoner-visible only after the outer transaction commits.
   *
   * Returns the patched writ (post-`setWritExt`).
   */
  petition(writId: string, extRequest: PetitionExtRequest): Promise<WritDoc>;

  /**
   * Withdraw a held writ by transitioning it to `cancelled`.
   *
   * Thin wrapper around `clerk.transition(writId, 'cancelled',
   * { resolution: reason })`. No source check, no owner check,
   * no ext check. Reason is passed through verbatim — undefined
   * stays undefined (no fabricated default).
   */
  withdraw(writId: string, reason?: string): Promise<WritDoc>;

  /**
   * Return `true` when `source` is in the kit-static petitioner
   * registry. Reads the sealed in-memory registry; cheap to call.
   */
  isSourceRegistered(source: string): boolean;

  /**
   * Return `true` when `source` is currently in the live
   * `disabledSources` config list. Re-reads `guild.json` on
   * every call so operators can hot-edit (D20).
   */
  isSourceDisabled(source: string): boolean;

  /**
   * Return projections of every registered petitioner descriptor.
   *
   * Surfaces the contract floor only — `source` and `description`
   * — per D19. Returns an empty array when no petitioners are
   * registered.
   */
  listPetitioners(): PetitionerDescriptor[];
}

/**
 * Lattice public types.
 *
 * All types exported from @shardworks/lattice-apparatus.
 *
 * The Lattice is the guild's notification substrate: a `lattice/pulses` book
 * that persists pulse records, a channel-factory contribution vocabulary
 * (`latticeChannels`) that lets external kits contribute push surfaces, and a
 * Phase 2 CDC dispatcher that fans newly-emitted pulses out to every
 * configured channel.
 *
 * Pulses are immutable event records — the only mutable field is
 * `deliveryState`, which the Lattice itself rewrites as dispatches progress.
 * There is no update or delete on the public API surface.
 */

import type { BookEntry } from '@shardworks/stacks-apparatus';

// ── Pulse document ───────────────────────────────────────────────────

/**
 * Delivery state for a pulse.
 *
 *   - `pending`   — written but not yet dispatched to any channel.
 *   - `delivered` — every configured channel returned ok=true.
 *   - `failed`    — at least one configured channel returned ok=false or
 *                   threw; the Lattice records the failure and does not
 *                   retry (best-effort one-shot per D8).
 */
export type PulseDeliveryState = 'pending' | 'delivered' | 'failed';

/**
 * A pulse document as stored in the `lattice/pulses` book.
 *
 * Pulses are emitted by observers (the Reckoner, future emitters) and
 * dispatched by the Lattice to every channel materialized from guild config.
 */
export interface PulseDoc extends BookEntry {
  /** Unique pulse id (`p-{base36_timestamp}-{hex_random}`). Sortable by creation time. */
  id: string;
  /**
   * Plugin id of the emitter that produced this pulse.
   *
   * The Lattice trusts the emitter to stamp its own source id — ownership
   * is convention-only (the Lattice does not forge or validate), mirroring
   * the plugin-keyed sub-slot convention used by `ClerkApi.setWritStatus`.
   */
  source: string;
  /**
   * Trigger type — the "what" axis of a pulse, independent of the source.
   *
   * Format: `{pluginId}.{kebab-suffix}` (e.g. `reckoner.writ-stuck`). Same
   * grammar Clerk uses for link kinds.
   */
  triggerType: string;
  /** Optional writ this pulse is about. Null for pulses that are not writ-scoped (e.g. queue-drained). */
  writId: string | null;
  /** Short human-readable title suitable for a notification headline. */
  title: string;
  /** Plain-text summary (one or two short lines). Degrades gracefully across channel backends. */
  summary: string;
  /**
   * Deep link into a surface that lets the patron act on the pulse.
   *
   * Always `null` in the MVP — no canonical public URL base exists yet.
   * Future commissions may populate this for pulses that have a sensible
   * remote-viewable URL.
   */
  linkUrl: string | null;
  /**
   * Structured payload keyed by triggerType. See individual emitters for the
   * concrete shapes (e.g. the Reckoner's writ-stuck context).
   */
  context: Record<string, unknown>;
  /** Current delivery state. Rewritten by the dispatcher. */
  deliveryState: PulseDeliveryState;
  /** Reason when `deliveryState` is `failed`. Absent on pending/delivered. */
  deliveryError?: string;
  /** ISO timestamp when the pulse was emitted. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
}

// ── Channel abstraction ──────────────────────────────────────────────

/**
 * Outcome returned by a channel's `send()`.
 *
 * Channels must never throw across the boundary — any error is reported as
 * `{ ok: false, error }` instead. This keeps the dispatcher simple and makes
 * the per-channel failure policy explicit.
 */
export type DeliveryOutcome =
  | { ok: true }
  | { ok: false; error: string };

/**
 * A materialized channel instance.
 *
 * Channels are created once at startup from per-channel instance config and
 * re-used across dispatches. `type` is the factory id (e.g. `discord-webhook`).
 */
export interface LatticeChannel {
  /** Factory type id — matches `LatticeChannelFactory.type`. */
  readonly type: string;
  /**
   * Deliver a pulse. Must never throw across the boundary; any error is
   * reported as `{ ok: false, error }` instead.
   */
  send(pulse: PulseDoc): Promise<DeliveryOutcome>;
}

/**
 * A channel factory contributed by a kit via `latticeChannels`.
 *
 * The factory builds a `LatticeChannel` from per-instance config drawn from
 * `guild.json`'s `lattice.channels` array. Instance config carries the
 * caller-provided fields (e.g. a `webhookUrlEnvVar` naming the env var
 * holding the Discord webhook URL) — secrets are resolved at send time,
 * never persisted.
 */
export interface LatticeChannelFactory {
  /** Factory type id. Must be unique across contributed factories. */
  readonly type: string;
  /**
   * Build a channel instance from the per-instance config drawn from
   * `lattice.channels[i]` (with the `type` field included).
   */
  create(instanceConfig: LatticeChannelInstanceConfig): LatticeChannel;
}

/**
 * Per-channel instance config as it appears in `guild.json`'s
 * `lattice.channels` array. The `type` field selects the factory; all other
 * fields are factory-specific.
 */
export interface LatticeChannelInstanceConfig {
  /** Factory type id — selects the channel factory. */
  type: string;
  /** Caller-supplied instance fields (webhook env var, discord channel id, etc.). */
  [field: string]: unknown;
}

// ── Kit contribution interface ───────────────────────────────────────

/**
 * Kit contribution interface for plugins that extend the Lattice with
 * additional channel factories. Contribute an array of factories under
 * `latticeChannels`; each factory becomes selectable via its `type` field in
 * `lattice.channels`.
 */
export interface LatticeKit {
  /** Channel factories contributed by this kit. */
  latticeChannels?: LatticeChannelFactory[];
}

// ── Config ───────────────────────────────────────────────────────────

/**
 * Lattice apparatus configuration — lives under the `lattice` key in
 * `guild.json`.
 */
export interface LatticeConfig {
  /**
   * Configured channel instances. Each entry is passed to the factory whose
   * `type` field matches `entry.type`. Multiple entries may share a type —
   * e.g. two Discord webhook channels pointing at different endpoints.
   *
   * Secrets (webhook URLs, tokens, …) are never placed in this array
   * directly; instead entries name an env var (convention per-factory) that
   * is read at send time.
   */
  channels?: LatticeChannelInstanceConfig[];
}

// Augment GuildConfig so `guild().guildConfig().lattice` is typed without
// requiring a manual type parameter at the call site.
declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    lattice?: LatticeConfig;
  }
}

// ── Request / filter types ───────────────────────────────────────────

/**
 * Request to emit a new pulse. The Lattice fills in `id`, `deliveryState`
 * (`'pending'`), and timestamps; the caller supplies everything else.
 */
export interface EmitPulseRequest {
  /** Plugin id of the emitter (stamped onto `pulse.source`). */
  source: string;
  /** Trigger type — fully-qualified `{pluginId}.{kebab-suffix}` id. */
  triggerType: string;
  /** Optional writ this pulse is about. Null for non-writ-scoped pulses. */
  writId?: string | null;
  /** Short human-readable title. */
  title: string;
  /** Plain-text summary. */
  summary: string;
  /** Optional deep link (always null in MVP). */
  linkUrl?: string | null;
  /** Structured payload keyed by trigger type. Defaults to `{}`. */
  context?: Record<string, unknown>;
}

/**
 * Filters accepted by `LatticeApi.list` / `LatticeApi.count`.
 */
export interface PulseFilters {
  /** Filter by triggerType. Accepts a single value or an array (OR). */
  triggerType?: string | string[];
  /** Filter by source plugin id. */
  source?: string;
  /** Only pulses created at or after this ISO timestamp. */
  since?: string;
  /** Only pulses created at or before this ISO timestamp. */
  until?: string;
  /** Filter by delivery state. Accepts a single value or an array (OR). */
  deliveryState?: PulseDeliveryState | PulseDeliveryState[];
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

// ── API ──────────────────────────────────────────────────────────────

/**
 * The Lattice's runtime API — retrieved via `guild().apparatus<LatticeApi>('lattice')`.
 *
 * The surface mirrors `ClerkApi`'s read-side shape: `emit`, `show`, `list`,
 * `count`, `resolveId`. There is no `update` or `delete` — pulses are
 * immutable event records. The only mutable field on a pulse is
 * `deliveryState`, and the Lattice itself is the only writer.
 */
export interface LatticeApi {
  /**
   * Emit a pulse. Assigns an id, timestamps, and `deliveryState: 'pending'`,
   * writes it to the pulses book, and returns the persisted document.
   *
   * Dispatch is handled asynchronously by the Lattice's Phase 2 CDC
   * watcher — `emit()` does not wait for delivery.
   */
  emit(request: EmitPulseRequest): Promise<PulseDoc>;

  /** Show a pulse by id. Throws if not found. */
  show(id: string): Promise<PulseDoc>;

  /**
   * Resolve a pulse id prefix to the full id. Throws when no pulse matches
   * or when the prefix is ambiguous.
   */
  resolveId(prefix: string): Promise<string>;

  /**
   * List pulses with optional filters, ordered by createdAt descending.
   * Default limit is 20; default `since` is 24h before now.
   */
  list(filters?: PulseFilters): Promise<PulseDoc[]>;

  /** Count pulses matching optional filters. */
  count(filters?: PulseFilters): Promise<number>;
}

